/// A kanban board — the top-level container.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Board {
    pub id: String,
    pub name: String,
    pub created_at: String,
    pub updated_at: String,
}

/// A column within a board, holding tasks in order.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Column {
    pub id: String,
    pub board_id: String,
    pub name: String,
    pub position: i32,
    pub created_at: String,
    pub updated_at: String,
}

/// A priority level (e.g. low, medium, high).
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Priority {
    pub id: String,
    pub name: String,
}

/// A task belonging to a column.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Task {
    pub id: String,
    pub column_id: String,
    pub title: String,
    pub description: String,
    pub priority_id: String,
    pub position: i32,
    pub created_at: String,
    pub updated_at: String,
}

/// Complete snapshot of a board's state.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct BoardState {
    pub board: Board,
    /// Sorted by position.
    pub columns: Vec<Column>,
    /// Sorted by column_id, then position.
    pub tasks: Vec<Task>,
    pub priorities: Vec<Priority>,
}

/// Partial update fields for a task.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct TaskChanges {
    pub title: Option<String>,
    pub description: Option<String>,
    pub priority_id: Option<String>,
    pub column_id: Option<String>,
    pub position: Option<i32>,
}

/// Partial update fields for a column.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct ColumnChanges {
    pub name: Option<String>,
    pub position: Option<i32>,
}

/// Filter criteria for listing tasks.
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct TaskFilter {
    pub column_id: Option<String>,
    pub priority_id: Option<String>,
}

/// What to do with orphaned tasks when their column is deleted.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum OrphanAction {
    MoveToFirst,
    Delete,
}

/// A typed SQL parameter placeholder value.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum SqlParam {
    Text(String),
    Int(i32),
}

/// The entity table being addressed by a position-update SQL statement.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum EntityTable {
    Column,
    Task,
}

impl EntityTable {
    /// The SQL table name. `column` is reserved, so we use `column_`.
    pub fn table_name(&self) -> &'static str {
        match self {
            EntityTable::Column => "column_",
            EntityTable::Task => "task",
        }
    }
}

use crate::core::error::DomainError;
use crate::core::types::{Column, Priority};

/// Maximum allowed length for a task title.
pub const MAX_TITLE_LENGTH: usize = 200;

/// Validate a task title is non-empty and within length limits.
pub fn validate_title(title: &str) -> Result<(), DomainError> {
    if title.is_empty() {
        return Err(DomainError::EmptyTitle);
    }
    if title.len() > MAX_TITLE_LENGTH {
        return Err(DomainError::TitleTooLong { max: MAX_TITLE_LENGTH });
    }
    Ok(())
}

/// Validate a column name is non-empty and unique within the existing columns.
pub fn validate_column_name(name: &str, existing: &[Column]) -> Result<(), DomainError> {
    if name.is_empty() {
        return Err(DomainError::EmptyColumnName);
    }
    if existing.iter().any(|c| c.name == name) {
        return Err(DomainError::DuplicateColumnName { name: name.to_string() });
    }
    Ok(())
}

/// Validate that a priority with the given ID exists in the provided list.
pub fn validate_priority(priority_id: &str, priorities: &[Priority]) -> Result<(), DomainError> {
    if priorities.iter().any(|p| p.id == priority_id) {
        return Ok(());
    }
    Err(DomainError::PriorityNotFound { id: priority_id.to_string() })
}

/// Validate that a column with the given ID exists in the provided list.
pub fn validate_column_exists(column_id: &str, columns: &[Column]) -> Result<(), DomainError> {
    if columns.iter().any(|c| c.id == column_id) {
        return Ok(());
    }
    Err(DomainError::ColumnNotFound { id: column_id.to_string() })
}

